// generar_208_cuidados_reorganizados.js
// CHIQUI Entre Señales — Reorganización de "Cuidados de hoy" + Arenero
//
// Qué hace este script:
// 1) app/registro-diario/page.tsx → "Cuidados básicos" y "Eventos
//    importantes" se fusionan en "Veterinario y salud" (primer grupo);
//    "Compré alimento" pasa a Alimentación; y para GATOS aparece el
//    grupo nuevo "Arenero" (Limpié el arenero / Cambié la arena /
//    Compré arena).
// 2) app/analisis/page.tsx → Rutinas de cuidado actualizadas a los
//    mismos grupos y emojis, incluyendo las 3 rutinas del arenero
//    (permite estimar cada cuánto comprar arena, igual que alimento).
// 3) app/dashboard/page.tsx → tarjeta "Cuidados recientes" con la
//    misma organización nueva.
//
// IMPORTANTE: antes de correr este script, ejecuta el SQL
// sql_208_arenero.sql en Supabase (New snippet), porque las columnas
// nuevas deben existir antes de que la app intente guardarlas.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_208_cuidados_reorganizados.js

const fs = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos escritos correctamente.')
  console.log('Recuerda: primero el SQL en Supabase, luego git add / commit / push.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
